class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int stability = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int hcf = findHCF(nums, i, j);
                if (hcf >= 2) {
                    stability = Math.max(stability, j - i + 1);
                }
            }
        }
        if (stability == 0) {
            return 0;
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] < 2) {
                count++;
            }
        }
        if (count <= maxC) {
            return stability;
        }
        return 1;
    }
    private int findHCF(int[] nums, int start, int end) {
        int hcf = nums[start];
        for (int i = start + 1; i <= end; i++) {
            hcf = gcd(hcf, nums[i]);
        }
        return hcf;
    }
    private int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
